    @app.route("/api/auth/login", methods=["POST"])
    def login():
        data = _get_json()
        identifier = _login_attempt_identifier(data)
        if _login_rate_limited(identifier, request.remote_addr):
            return (
                jsonify(
                    ok=False,
                    message="Terlalu banyak percobaan login. Coba lagi beberapa menit lagi.",
                    next_url=None,
                ),
                429,
            )
        result = _validate_login(data)
        _record_login_attempt(identifier, request.remote_addr, result.ok)
        if result.ok:
            user = _current_user()
            _log_audit_event(
                entity_type="auth",
                entity_id=user.id if user else None,
                action="LOGIN",
                actor=user,
                summary="Login berhasil.",
                details={"email": user.email if user else None, "role": user.role if user else None},
            )
        status = 200 if result.ok else 400
        return jsonify(result.__dict__), status

