@dataclass
class User:
    id: int
    email: str
    role: str
    name: str = ""
    theme: str = "silver_line"
    tier: str = "basic"
    selfie_path: str | None = None
    must_change_password: int = 0
    client_id: int | None = None
    site_id: int | None = None


class DuplicateSubmissionError(ValueError):
    pass


class CommunicationRateLimitError(ValueError):
    pass


def _persist_user(user: User) -> None:
    session["user"] = {
        "id": user.id,
        "email": user.email,
        "role": user.role,
        "name": user.name,
        "theme": user.theme,
        "tier": user.tier,
        "selfie_path": user.selfie_path,
        "must_change_password": user.must_change_password,
        "client_id": user.client_id,
        "site_id": user.site_id,
        "branch_id": user.site_id,
    }


def _current_user() -> User | None:
    data = session.get("user") or {}
    if not data:
        return None
    user_id = int(data.get("id") or 0)
    if user_id:
        row = _get_user_by_id(user_id)
        if not row or int(row["is_active"] or 0) != 1:
            session.pop("user", None)
            return None
        role = _normalize_role(row["role"] if "role" in row.keys() else data.get("role", "employee"))
        email = row["email"] if "email" in row.keys() else data.get("email", "")
        name = row["name"] if "name" in row.keys() else data.get("name", "")
        tier = row["tier"] if "tier" in row.keys() else data.get("tier", "basic")
        theme = row["theme_preference"] if "theme_preference" in row.keys() and row["theme_preference"] else data.get("theme", "silver_line")
        client_id = row["client_id"] if "client_id" in row.keys() else data.get("client_id")
        site_id = row["site_id"] if "site_id" in row.keys() else data.get("site_id")
        if (site_id is None or site_id == "") and "branch_id" in row.keys():
            site_id = row["branch_id"]
    else:
        role = _normalize_role(data.get("role", "employee"))
        email = data.get("email", "")
        name = data.get("name", "")
        tier = data.get("tier", "basic")
        theme = data.get("theme", "silver_line")
        client_id = data.get("client_id")
        site_id = data.get("site_id") or data.get("branch_id")
    return User(
        id=int(data.get("id") or 0),
        email=email,
        role=role,
        name=name,
        theme=_normalize_enabled_theme(theme),
        tier=_normalize_user_tier(str(tier or "basic")),
        selfie_path=data.get("selfie_path"),
        must_change_password=int(data.get("must_change_password") or 0),
        client_id=int(client_id) if str(client_id).isdigit() and int(client_id) > 0 else None,
        site_id=int(site_id) if str(site_id).isdigit() and int(site_id) > 0 else None,
    )


def _api_v1_user() -> User | None:
    g.api_access_auth = None
    user = _current_user()
    if user:
        g.api_access_auth = {"auth_type": "session", "client_id": user.client_id, "site_id": user.site_id}
        return user
    raw_token = (request.headers.get("X-API-Key") or "").strip()
    auth_header = (request.headers.get("Authorization") or "").strip()
    if not raw_token and auth_header.lower().startswith("bearer "):
        raw_token = auth_header[7:].strip()
    if not raw_token:
        return None
    token_row = _api_access_token_lookup(raw_token)
    branch_id_raw = (request.args.get("branch_id") or request.args.get("site_id") or "").strip()
    resolved_site_id = int(branch_id_raw) if branch_id_raw.isdigit() and int(branch_id_raw) > 0 else None
    if token_row:
        token_client_id = int(token_row["client_id"])
        g.api_access_auth = {
            "auth_type": "token",
            "token_id": int(token_row["id"]),
            "token_row": token_row,
            "client_id": token_client_id,
            "site_id": resolved_site_id,
        }
        return User(
            id=0,
            email=f"api-client-{token_client_id}@system.local",
            role="client_admin",
            name=token_row.get("label") or "API Access",
            tier="enterprise",
            client_id=token_client_id,
            site_id=None,
        )
    if not API_ACCESS_TOKEN or not hmac.compare_digest(raw_token, API_ACCESS_TOKEN):
        return None
    client_id_raw = (request.args.get("client_id") or "").strip()
    legacy_client_id = int(client_id_raw) if client_id_raw.isdigit() and int(client_id_raw) > 0 else None
    g.api_access_auth = {"auth_type": "legacy_token", "client_id": legacy_client_id, "site_id": resolved_site_id}
    return User(
        id=0,
        email="api@system.local",
        role="hr_superadmin",
        name="API Access",
        tier="enterprise",
        client_id=legacy_client_id,
        site_id=None,
    )


def _api_v1_token_supplied() -> bool:
    raw_token = (request.headers.get("X-API-Key") or "").strip()
    auth_header = (request.headers.get("Authorization") or "").strip()
    return bool(raw_token or auth_header.lower().startswith("bearer "))


def _require_role(user: User | None, allowed_roles: set[str]) -> None:
    if not user or user.role not in allowed_roles:
        abort(403)


def _require_api_role(user: User | None, allowed_roles: set[str]):
    if not user or user.role not in allowed_roles:
        return _json_forbidden()
    return None


def _require_admin(user: User | None) -> None:
    _require_role(user, ADMIN_ROLES)


def _client_admin_client_id(user: User | None) -> int | None:
    if not user or user.role != "client_admin":
        return None
    if isinstance(user.client_id, int) and user.client_id > 0:
        return int(user.client_id)
    return None


def _approver_client_scope_id(user: User | None) -> int | None:
    if not user:
        return None
    if user.role == "client_admin":
        return _client_admin_client_id(user)
    if user.role == "manager_operational":
        if isinstance(user.client_id, int) and user.client_id > 0:
            return int(user.client_id)
    return None


def _client_user_client_id(user: User | None) -> int | None:
    if not user or user.role not in CLIENT_ROLES:
        return None
    if isinstance(user.client_id, int) and user.client_id > 0:
        return int(user.client_id)
    return None


def get_current_client_scope(user: User | None = None) -> int | None:
    current = user or _current_user()
    if not current:
        return None
    if current.role == "hr_superadmin":
        return None
    if current.role == "client_admin":
        return _client_admin_client_id(current)
    if current.role in CLIENT_ROLES:
        return _client_user_client_id(current)
    if isinstance(current.client_id, int) and current.client_id > 0:
        return int(current.client_id)
    return None


def _client_user_site_id(user: User | None) -> int | None:
    if not user or user.role not in CLIENT_ROLES:
        return None
    if isinstance(user.site_id, int) and user.site_id > 0:
        return int(user.site_id)
    return None


def _require_client_user(user: User | None) -> None:
    if not user or user.role not in CLIENT_ROLES:
        abort(403)


def _require_client_admin(user: User | None) -> None:
    if not user or user.role != "client_admin":
        abort(403)


def _require_client_admin_client(user: User | None, client_id: int | None) -> None:
    if not user or user.role != "client_admin":
        return
    scope_id = _client_admin_client_id(user)
    if not scope_id or not client_id or int(client_id) != scope_id:
        abort(403)


def _require_client_admin_site(user: User | None, site_id: int | None) -> None:
    if not user or user.role != "client_admin":
        return
    site = _get_site_by_id(site_id) if site_id else None
    client_id = int(site["client_id"]) if site and site["client_id"] is not None else None
    _require_client_admin_client(user, client_id)


def _client_site_context(user: User | None) -> tuple[int, int, dict, dict]:
    _require_client_user(user)
    client_id = _client_user_client_id(user)
    site_id = _client_user_site_id(user)
    if not client_id or not site_id:
        abort(403)
    site_row = _get_site_by_id(site_id)
    if not site_row:
        abort(404)
    if int(_row_get(site_row, "client_id") or 0) != client_id:
        abort(403)
    client_row = _get_client_by_id(client_id)
    client = dict(client_row) if client_row else {"id": client_id, "name": "Client"}
    return client_id, site_id, _normalize_site_shift_config(dict(site_row)), client


def _require_hr_or_client_admin(user: User | None) -> None:
    if not user or user.role not in ADMIN_ROLES:
        abort(403)


def _require_manual_approver(user: User | None) -> None:
    if not user or not _can_approve_manual(user):
        abort(403)


def _require_hr_superadmin(user: User | None) -> None:
    _require_role(user, {"hr_superadmin"})


def _json_forbidden():
    return jsonify(ok=False, message="Unauthorized."), 403


def _pro_required_response(feature_label: str):
    return (
        jsonify(
            ok=False,
            message=f"{feature_label} hanya tersedia untuk HRIS PRO dan Enterprise.",
        ),
        403,
    )


def _normalize_user_tier(value: str | None) -> str:
    tier = (value or "pro").strip().lower()
    if tier == "basic":
        return "pro"
    return tier if tier in USER_TIER_OPTIONS else "pro"


COMMUNICATION_TIER_OPTIONS = ("pro", "pro_plus", "enterprise")


def _normalize_communication_tier(value: str | None) -> str:
    tier = (value or "pro").strip().lower()
    if tier == "basic":
        return "pro"
    return tier if tier in COMMUNICATION_TIER_OPTIONS else "pro"


def _normalize_theme(value: str | None) -> str:
    theme = (value or "dark").strip().lower()
    return theme if theme in THEME_OPTIONS else "dark"


def _enabled_extra_themes() -> list[str]:
    return THEME_SETTING_OPTIONS.copy() if _extra_themes_enabled() else []


def _extra_themes_enabled() -> bool:
    value = _get_app_setting("extra_themes_enabled", True)
    if isinstance(value, bool):
        return value
    if isinstance(value, str):
        return value.strip().lower() not in {"0", "false", "off", "no"}
    return bool(value)


def _set_extra_themes_enabled(enabled: object) -> bool:
    next_enabled = bool(enabled)
    _set_app_setting("extra_themes_enabled", next_enabled)
    _set_app_setting("enabled_extra_themes", THEME_SETTING_OPTIONS.copy() if next_enabled else [])
    if not next_enabled:
        _reset_extra_theme_preferences()
    return next_enabled


def _reset_extra_theme_preferences() -> None:
    placeholders = ",".join("?" for _ in THEME_SETTING_OPTIONS)
    conn = _db_connect()
    try:
        if _table_exists(conn, "users"):
            conn.execute(
                f"""
                UPDATE users
                SET theme_preference = 'dark', updated_at = ?
                WHERE lower(COALESCE(theme_preference, '')) IN ({placeholders})
                """,
                (_now_ts(), *THEME_SETTING_OPTIONS),
            )
        if _table_exists(conn, "clients"):
            conn.execute(
                f"""
                UPDATE clients
                SET client_theme = 'dark', updated_at = ?
                WHERE lower(COALESCE(client_theme, '')) IN ({placeholders})
                """,
                (_now_ts(), *THEME_SETTING_OPTIONS),
            )
    finally:
        conn.commit()
        conn.close()


def _set_enabled_extra_themes(themes: object) -> list[str]:
    if isinstance(themes, bool):
        return _enabled_extra_themes() if _set_extra_themes_enabled(themes) else []
    if isinstance(themes, dict):
        enabled = any(bool(value) for value in themes.values())
    elif isinstance(themes, list):
        enabled = bool(themes)
    else:
        enabled = bool(themes)
    return _enabled_extra_themes() if _set_extra_themes_enabled(enabled) else []


def _enabled_theme_options() -> list[str]:
    return [*THEME_DEFAULT_OPTIONS, *_enabled_extra_themes()]


def _enabled_theme_setting_options() -> list[str]:
    return _enabled_extra_themes()


def _normalize_enabled_theme(value: str | None) -> str:
    theme = _normalize_theme(value)
    return theme if theme in _enabled_theme_options() else "dark"


def _resolve_theme_preference(user: User | None) -> str:
    if not user:
        return "dark"
    if user.role != "client_admin" and user.client_id:
        client = _get_client_by_id(user.client_id)
        if client and "client_theme" in client.keys() and client["client_theme"]:
            return _normalize_enabled_theme(client["client_theme"])
    return _normalize_enabled_theme(user.theme)


def _normalize_role(value: str | None) -> str:
    role = (value or "").strip().lower()
    return ROLE_ALIASES.get(role, role)


def _default_role_permissions(role: str) -> dict[str, bool]:
    defaults = {key: True for key in ROLE_PERMISSION_KEYS}
    if role == "hr_superadmin":
        return defaults
    if role in CLIENT_ROLES:
        for key in ROLE_PERMISSION_KEYS:
            defaults[key] = False
    defaults["manage_settings_codes"] = False
    defaults["manage_settings_password"] = False
    return defaults


def _get_role_permissions(role: str) -> dict[str, bool]:
    conn = _db_connect()
    try:
        if not _table_exists(conn, "role_permissions"):
            return _default_role_permissions(role)
        row = conn.execute(
            "SELECT permissions_json FROM role_permissions WHERE role = ?",
            (role,),
        ).fetchone()
        if not row:
            return _default_role_permissions(role)
        try:
            payload = json.loads(row["permissions_json"] or "{}")
        except json.JSONDecodeError:
            return _default_role_permissions(role)
        merged = _default_role_permissions(role)
        for key in ROLE_PERMISSION_KEYS:
            if key in payload:
                merged[key] = bool(payload[key])
        return merged
    finally:
        conn.close()


def _set_role_permissions(role: str, permissions: dict[str, bool]) -> None:
    if role == "hr_superadmin":
        permissions = {key: True for key in ROLE_PERMISSION_KEYS}
    payload = {key: bool(permissions.get(key)) for key in ROLE_PERMISSION_KEYS}
    conn = _db_connect()
    try:
        conn.execute(
            """
            INSERT INTO role_permissions (role, permissions_json, updated_at)
            VALUES (?, ?, ?)
            ON CONFLICT(role) DO UPDATE SET
                permissions_json = excluded.permissions_json,
                updated_at = excluded.updated_at
            """,
            (role, json.dumps(payload, ensure_ascii=True), _now_ts()),
        )
    finally:
        conn.commit()
        conn.close()


def _has_role_permission(role: str, permission: str) -> bool:
    if role == "hr_superadmin":
        return True
    perms = _get_role_permissions(role)
    return bool(perms.get(permission))


