def _policy_with_defaults(row: sqlite3.Row | None) -> dict:
    policy = DEFAULT_ATTENDANCE_POLICY.copy()
    if not row:
        return policy
    if "id" in row.keys():
        policy["policy_id"] = row["id"]
    for key in policy.keys():
        if key in row.keys() and row[key] is not None:
            policy[key] = row[key]
    policy["payroll_scheme"] = _normalize_payroll_scheme(policy.get("payroll_scheme"))
    policy["payroll_schedule"] = _normalize_payroll_schedule(policy.get("payroll_schedule"))
    return policy


def _resolve_attendance_policy(
    site_id: int | None,
    client_id: int | None,
    shift_id: int | None,
    as_of_date: str | None = None,
) -> dict:
    conn = _db_connect()
    try:
        if not _table_exists(conn, "attendance_policies"):
            return DEFAULT_ATTENDANCE_POLICY.copy()
        today = _normalize_date_input(as_of_date) or _today_key()
        if site_id:
            cur = conn.execute(
                """
                SELECT *
                FROM attendance_policies
                WHERE scope_type = 'SITE'
                  AND site_id = ?
                  AND (shift_id IS NULL OR shift_id = ?)
                  AND effective_from <= ?
                  AND (effective_to IS NULL OR effective_to = '' OR effective_to >= ?)
                ORDER BY CASE WHEN shift_id = ? THEN 0 ELSE 1 END, effective_from DESC
                LIMIT 1
                """,
                (site_id, shift_id, today, today, shift_id),
            )
            row = cur.fetchone()
            if row:
                return _policy_with_defaults(row)
        if client_id:
            cur = conn.execute(
                """
                SELECT *
                FROM attendance_policies
                WHERE scope_type = 'CLIENT'
                  AND client_id = ?
                  AND (shift_id IS NULL OR shift_id = ?)
                  AND effective_from <= ?
                  AND (effective_to IS NULL OR effective_to = '' OR effective_to >= ?)
                ORDER BY CASE WHEN shift_id = ? THEN 0 ELSE 1 END, effective_from DESC
                LIMIT 1
                """,
                (client_id, shift_id, today, today, shift_id),
            )
            row = cur.fetchone()
            if row:
                return _policy_with_defaults(row)
        cur = conn.execute(
            """
            SELECT *
            FROM attendance_policies
            WHERE scope_type = 'GLOBAL'
              AND (shift_id IS NULL OR shift_id = ?)
              AND effective_from <= ?
              AND (effective_to IS NULL OR effective_to = '' OR effective_to >= ?)
            ORDER BY CASE WHEN shift_id = ? THEN 0 ELSE 1 END, effective_from DESC
            LIMIT 1
            """,
            (shift_id, today, today, shift_id),
        )
        row = cur.fetchone()
        if row:
            return _policy_with_defaults(row)
        return DEFAULT_ATTENDANCE_POLICY.copy()
    finally:
        conn.close()


