def _list_employee_users() -> list[dict]:
    conn = _db_connect()
    try:
        cur = conn.execute(
            """
            SELECT
                u.id,
                u.name,
                u.email,
                u.is_active,
                COALESCE(
                    (
                        SELECT a.client_id
                        FROM assignments a
                        WHERE a.employee_user_id = u.id
                          AND upper(COALESCE(a.status, 'ACTIVE')) = 'ACTIVE'
                          AND (a.end_date IS NULL OR a.end_date = '' OR a.end_date >= date('now'))
                        ORDER BY a.start_date DESC, a.id DESC
                        LIMIT 1
                    ),
                    u.client_id
                ) AS client_id,
                COALESCE(
                    (
                        SELECT a.site_id
                        FROM assignments a
                        WHERE a.employee_user_id = u.id
                          AND upper(COALESCE(a.status, 'ACTIVE')) = 'ACTIVE'
                          AND (a.end_date IS NULL OR a.end_date = '' OR a.end_date >= date('now'))
                        ORDER BY a.start_date DESC, a.id DESC
                        LIMIT 1
                    ),
                    u.site_id
                ) AS site_id
            FROM users u
            WHERE u.role = 'employee'
            ORDER BY name, email
            """
        )
        return [dict(row) for row in cur.fetchall()]
    finally:
        conn.close()


