def _create_assignment(
    employee_user_id: int,
    site_id: int,
    shift_id: int | None,
    job_title: str | None,
    start_date: str,
    end_date: str | None,
    status: str,
) -> int:
    conn = _db_connect()
    try:
        conn.execute("BEGIN IMMEDIATE")
        return _create_assignment_with_conn(
            conn,
            employee_user_id=employee_user_id,
            site_id=site_id,
            shift_id=shift_id,
            job_title=job_title,
            start_date=start_date,
            end_date=end_date,
            status=status,
        )
    finally:
        conn.commit()
        conn.close()


def _create_assignment_with_conn(
    conn: sqlite3.Connection,
    *,
    employee_user_id: int,
    site_id: int,
    shift_id: int | None,
    job_title: str | None,
    start_date: str,
    end_date: str | None,
    status: str,
) -> int:
    if status == "ENDED" and not end_date:
        end_date = start_date
    if status == "ACTIVE":
        conn.execute(
            """
            UPDATE assignments
            SET status = 'ENDED', end_date = ?, updated_at = ?
            WHERE employee_user_id = ? AND status = 'ACTIVE'
            """,
            (start_date, _now_ts(), employee_user_id),
        )
    site_row = conn.execute("SELECT client_id FROM sites WHERE id = ?", (site_id,)).fetchone()
    client_id = site_row["client_id"] if site_row else None
    cur = conn.execute(
        """
        INSERT INTO assignments (
            employee_user_id, client_id, site_id, branch_id, shift_id, job_title, start_date, end_date,
            status, created_at, updated_at
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            employee_user_id,
            client_id,
            site_id,
            site_id,
            shift_id,
            job_title,
            start_date,
            end_date,
            status,
            _now_ts(),
            _now_ts(),
        ),
    )
    return int(cur.lastrowid)


def _create_assignment_with_log(
    *,
    actor: User | None,
    employee_user_id: int,
    site_id: int,
    shift_id: int | None,
    job_title: str | None,
    start_date: str,
    end_date: str | None,
    status: str,
    summary: str,
    portal: str,
    extra_details: dict | None = None,
) -> int:
    assignment_id = _create_assignment(
        employee_user_id=employee_user_id,
        site_id=site_id,
        shift_id=shift_id,
        job_title=job_title,
        start_date=start_date,
        end_date=end_date,
        status=status,
    )
    details: dict = {
        "employee_user_id": employee_user_id,
        "site_id": site_id,
        "shift_id": shift_id,
        "job_title": job_title,
        "start_date": start_date,
        "end_date": end_date,
        "status": status,
        "portal": portal,
    }
    if extra_details:
        details.update(extra_details)
    _log_audit_event(
        entity_type="assignment",
        entity_id=assignment_id,
        action="CREATE",
        actor=actor,
        summary=summary,
        details=details,
    )
    return assignment_id


