def _seed_users(conn: sqlite3.Connection) -> None:
    for seed in SEED_USERS:
        email = seed["email"].lower()
        cur = conn.execute("SELECT id FROM users WHERE email = ?", (email,))
        if cur.fetchone():
            continue
        conn.execute(
            """
            INSERT INTO users (
                name, email, role, password_hash, is_active,
                created_at, updated_at, must_change_password, client_id, tier
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                seed.get("name") or "",
                email,
                _normalize_role(seed["role"]),
                generate_password_hash(seed["password"]),
                1,
                _now_ts(),
                _now_ts(),
                0,
                seed.get("client_id"),
                _normalize_user_tier(seed.get("tier")),
            ),
        )


def _seed_employees(conn: sqlite3.Connection) -> None:
    if not _table_exists(conn, "employees"):
        return
    for seed in SEED_EMPLOYEES:
        email = (seed.get("email") or "").lower()
        nik = seed.get("nik") or ""
        cur = conn.execute(
            "SELECT id FROM employees WHERE email = ? OR nik = ?",
            (email, nik),
        )
        if cur.fetchone():
            continue
        conn.execute(
            """
            INSERT INTO employees (
                nik, name, email, no_hp, address, gender,
                status_nikah, notes, is_active, created_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                seed.get("nik") or "",
                seed.get("name") or "",
                email,
                seed.get("no_hp") or "",
                seed.get("address") or "",
                seed.get("gender") or "",
                seed.get("status_nikah") or "",
                seed.get("notes") or None,
                int(seed.get("is_active") or 0),
                _now_ts(),
            ),
        )


def _employee_by_id(employee_id: str | int | None) -> dict | None:
    try:
        target = int(employee_id)
    except (TypeError, ValueError):
        return None
    for employee in _employees():
        if int(employee.get("id", 0)) == target:
            return employee
    return None


def _normalize_addon_key(value: object) -> str:
    key = str(value or "").strip().lower().replace("-", "_")
    return ADDON_FEATURE_ALIASES.get(key, key)


def _addons_from_value(value: object) -> list[str]:
    if value is None:
        return []
    payload: object = value
    if isinstance(value, str):
        raw = value.strip()
        if not raw:
            return []
        try:
            payload = json.loads(raw)
        except json.JSONDecodeError:
            payload = [part.strip() for part in raw.split(",")]
    if isinstance(payload, dict):
        items = [key for key, enabled in payload.items() if enabled]
    elif isinstance(payload, list):
        items = payload
    else:
        items = []
    normalized: list[str] = []
    for item in items:
        key = _normalize_addon_key(item)
        if key and key in ADDON_ALLOWED and key not in normalized:
            normalized.append(key)
    return normalized


def _addons_json(value: object) -> str:
    return json.dumps(_addons_from_value(value), ensure_ascii=True)


def _owner_suite_mode_from_addons(addons: object) -> str:
    normalized = _addons_from_value(addons)
    active = set(normalized)
    if ADDON_ENTERPRISE_TIER in active:
        return OWNER_SUITE_ENTERPRISE
    if ADDON_HRIS_PRO_PLUS in active:
        return OWNER_SUITE_PRO_PLUS
    if ADDON_HRIS_PRO in active:
        return OWNER_SUITE_PRO
    if any(addon in active for addon in ADDON_ENTERPRISE_AUTO_ENABLED):
        return OWNER_SUITE_PRO_PLUS
    return OWNER_SUITE_PRO


def _normalize_global_addons(addons: object) -> list[str]:
    normalized = _addons_from_value(addons)
    active = set(normalized)
    mode = _owner_suite_mode_from_addons(normalized)
    active -= ADDON_OWNER_MODE_KEYS
    if ADDON_BILLING_ENGINE in active or ADDON_CONTRACT_MANAGEMENT in active:
        active.add(ADDON_BILLING_ENGINE)
        active.add(ADDON_CONTRACT_MANAGEMENT)
    if mode == OWNER_SUITE_ENTERPRISE:
        active |= ADDON_ENTERPRISE_AUTO_ENABLED
    elif mode == OWNER_SUITE_PRO:
        active -= ADDON_PRO_AUTO_DISABLED
    if ADDON_COMMUNICATION_INCIDENT in active:
        active.add(ADDON_COMMUNICATION_ANNOUNCEMENT)
        active.add(ADDON_COMMUNICATION_CHAT)
    if ADDON_COMMUNICATION_ANNOUNCEMENT in active:
        active.add(ADDON_COMMUNICATION_CHAT)
    mode_key = {
        OWNER_SUITE_ENTERPRISE: ADDON_ENTERPRISE_TIER,
        OWNER_SUITE_PRO_PLUS: ADDON_HRIS_PRO_PLUS,
        OWNER_SUITE_PRO: ADDON_HRIS_PRO,
    }[mode]
    ordered = [mode_key]
    ordered.extend(addon for addon in ADDON_OWNER_ORDER if addon in active and addon not in ADDON_OWNER_MODE_KEYS)
    return ordered


def _get_app_setting(key: str, default: object = None) -> object:
    conn = _db_connect()
    try:
        if not _table_exists(conn, "app_settings"):
            return default
        row = conn.execute("SELECT value FROM app_settings WHERE key = ?", (key,)).fetchone()
        if not row:
            return default
        try:
            return json.loads(row["value"])
        except json.JSONDecodeError:
            return default
    finally:
        conn.close()


def _set_app_setting(key: str, value: object) -> None:
    conn = _db_connect()
    try:
        conn.execute(
            """
            INSERT INTO app_settings (key, value, updated_at)
            VALUES (?, ?, ?)
            ON CONFLICT(key) DO UPDATE SET
                value = excluded.value,
                updated_at = excluded.updated_at
            """,
            (key, json.dumps(value, ensure_ascii=True), _now_ts()),
        )
    finally:
        conn.commit()
        conn.close()


def _global_addons() -> list[str]:
    return _normalize_global_addons(_get_app_setting("global_addons", []))


def _set_global_addons(addons: object) -> list[str]:
    normalized = _normalize_global_addons(addons)
    _set_app_setting("global_addons", normalized)
    return normalized


def _normalize_client_package(value: object) -> str:
    package = str(value or "").strip().upper()
    if package == CLIENT_PACKAGE_BASIC:
        return CLIENT_PACKAGE_PRO
    return package if package in CLIENT_PACKAGE_OPTIONS else CLIENT_PACKAGE_PRO


def _normalize_billing_type(value: object) -> str:
    billing_type = str(value or "").strip().upper()
    return billing_type if billing_type in BILLING_TYPE_OPTIONS else BILLING_TYPE_PER_HEAD


def _phase15_addons_from_value(value: object) -> list[str]:
    return [key for key in _addons_from_value(value) if key in CLIENT_ADDON_OPTIONS]


def _get_client_package(client_id: int | None) -> str:
    if not client_id:
        return CLIENT_PACKAGE_PRO
    conn = _db_connect()
    try:
        if not _table_exists(conn, "client_packages"):
            return CLIENT_PACKAGE_PRO
        row = conn.execute(
            """
            SELECT package_type FROM client_packages
            WHERE client_id = ? AND is_active = 1
            ORDER BY id DESC
            LIMIT 1
            """,
            (client_id,),
        ).fetchone()
        return _normalize_client_package(row["package_type"] if row else None)
    finally:
        conn.close()


def _set_client_package(client_id: int, package_type: object) -> str:
    package = _normalize_client_package(package_type)
    now = _now_ts()
    conn = _db_connect()
    try:
        conn.execute(
            "UPDATE client_packages SET is_active = 0, updated_at = ? WHERE client_id = ? AND is_active = 1",
            (now, client_id),
        )
        conn.execute(
            """
            INSERT INTO client_packages (client_id, package_type, is_active, created_at, updated_at)
            VALUES (?, ?, 1, ?, ?)
            """,
            (client_id, package, now, now),
        )
    finally:
        conn.commit()
        conn.close()
    return package


def _list_client_addons(client_id: int | None) -> list[str]:
    if not client_id:
        return []
    conn = _db_connect()
    try:
        if not _table_exists(conn, "client_addons"):
            client = _get_client_by_id(client_id)
            return _phase15_addons_from_value(_row_get(client, "addons", "[]") if client else [])
        rows = conn.execute(
            """
            SELECT addon_key, is_enabled FROM client_addons
            WHERE client_id = ?
            ORDER BY addon_key
            """,
            (client_id,),
        ).fetchall()
        if rows:
            return _phase15_addons_from_value([row["addon_key"] for row in rows if row["is_enabled"]])
        client = conn.execute("SELECT addons FROM clients WHERE id = ?", (client_id,)).fetchone() if _table_exists(conn, "clients") else None
        return _phase15_addons_from_value(_row_get(client, "addons", "[]") if client else [])
    finally:
        conn.close()


def _set_client_addons(client_id: int, addons: object) -> list[str]:
    active = set(_phase15_addons_from_value(addons))
    now = _now_ts()
    conn = _db_connect()
    try:
        for addon_key in CLIENT_ADDON_OPTIONS:
            conn.execute(
                """
                INSERT INTO client_addons (client_id, addon_key, is_enabled, created_at, updated_at)
                VALUES (?, ?, ?, ?, ?)
                ON CONFLICT(client_id, addon_key) DO UPDATE SET
                    is_enabled = excluded.is_enabled,
                    updated_at = excluded.updated_at
                """,
                (client_id, addon_key, 1 if addon_key in active else 0, now, now),
            )
        if _table_exists(conn, "clients"):
            conn.execute(
                "UPDATE clients SET addons = ?, updated_at = ? WHERE id = ?",
                (_addons_json(sorted(active)), now, client_id),
            )
    finally:
        conn.commit()
        conn.close()
    return sorted(active)


def _client_package_supports_custom_addons(package: str | None) -> bool:
    return _normalize_client_package(package) in {CLIENT_PACKAGE_PRO_PLUS, CLIENT_PACKAGE_ENTERPRISE}


def _phase15_subscription(client_id: int | None) -> dict:
    package = _get_client_package(client_id)
    addons = _list_client_addons(client_id)
    return {
        "package": package,
        "addons": addons,
        "billing_enabled": _phase15_global_enabled(ADDON_BILLING_ENGINE),
        "contract_enabled": _phase15_global_enabled(ADDON_CONTRACT_MANAGEMENT),
        "sla_enabled": _phase15_global_enabled(ADDON_SLA_TRACKING),
    }


def _subscription_package_label(package: str | None) -> str:
    value = _normalize_client_package(package)
    if value == CLIENT_PACKAGE_PRO_PLUS:
        return "Pro Plus"
    if value == CLIENT_PACKAGE_ENTERPRISE:
        return "Enterprise"
    return "Pro"


def _subscription_package_description(package: str | None) -> str:
    value = _normalize_client_package(package)
    if value == CLIENT_PACKAGE_ENTERPRISE:
        return "Paket penuh untuk operasi lanjutan, add-on lengkap, dan integrasi enterprise."
    if value == CLIENT_PACKAGE_PRO_PLUS:
        return "Paket pro dengan add-on custom sesuai kebutuhan client."
    return "Paket inti operasional untuk workflow HRIS harian."


def _phase15_global_enabled(addon_key: str) -> bool:
    return addon_key in _global_addons()


def _phase15_user_client_id(user: User | None) -> int | None:
    if not user:
        return None
    if user.role == "client_admin":
        return _client_admin_client_id(user)
    if isinstance(user.client_id, int) and user.client_id > 0:
        return int(user.client_id)
    return None


