def _save_client_contract(
    client_id: int,
    contract_no: str,
    start_date: str | None,
    end_date: str | None,
    notice_period_days: int,
    scope_summary: str | None,
    sla_summary: str | None,
) -> None:
    now = _now_ts()
    conn = _db_connect()
    try:
        conn.execute(
            "UPDATE client_contracts SET is_active = 0, updated_at = ? WHERE client_id = ? AND is_active = 1",
            (now, client_id),
        )
        conn.execute(
            """
            INSERT INTO client_contracts (
                client_id, contract_no, start_date, end_date, notice_period_days,
                scope_summary, sla_summary, is_active, created_at, updated_at
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, 1, ?, ?)
            """,
            (
                client_id,
                contract_no,
                start_date,
                end_date,
                notice_period_days,
                scope_summary,
                sla_summary,
                now,
                now,
            ),
        )
    finally:
        conn.commit()
        conn.close()


