def _can_approve_manual(user: User) -> bool:
    return user.role in APPROVER_ROLES


def _is_pro(user: User) -> bool:
    """Check if user has PRO tier access"""
    if _owner_suite_mode() in {OWNER_SUITE_PRO, OWNER_SUITE_PRO_PLUS, OWNER_SUITE_ENTERPRISE}:
        return True
    if not user:
        return False
    if user.role == "hr_superadmin":
        return True
    if _is_enterprise(user):
        return True
    if not hasattr(user, 'tier'):
        return False
    return _normalize_user_tier(user.tier) in {"pro", "pro_plus", "enterprise"}


def _is_enterprise(user: User) -> bool:
    """Check if user has ENTERPRISE tier access"""
    if _owner_suite_mode() == OWNER_SUITE_ENTERPRISE:
        return True
    if not user or not hasattr(user, 'tier'):
        return False
    if user.role in ADMIN_ROLES and ADDON_ENTERPRISE_TIER in _global_addons():
        return True
    return _normalize_user_tier(user.tier) == "enterprise"


def _owner_suite_mode() -> str:
    return _owner_suite_mode_from_addons(_global_addons())


def _hris_brand_title() -> str:
    mode = _owner_suite_mode()
    if mode == OWNER_SUITE_ENTERPRISE:
        return "HRIS ENTERPRISE"
    if mode == OWNER_SUITE_PRO_PLUS:
        return "HRIS PRO PLUS"
    return "HRIS PRO"


def _effective_permissions_for(user: User | None) -> dict[str, bool]:
    if not user:
        return {}
    permissions = _get_role_permissions(user.role)
    permissions["view_calendar"] = bool(permissions.get("view_calendar")) and _calendar_feature_enabled(user)
    permissions["view_ai_analysis"] = bool(permissions.get("view_ai_analysis")) and _ai_analysis_feature_enabled(user)
    permissions["view_patrol_ops"] = bool(permissions.get("view_patrol")) and _patrol_ops_admin_enabled(user)
    permissions["view_billing"] = bool(permissions.get("view_billing")) and _billing_feature_enabled(user)
    permissions["view_contract"] = bool(permissions.get("view_contract")) and _contract_feature_enabled(user)
    return permissions


def _leave_request_overlaps(
    employee_email: str,
    date_from: str,
    date_to: str,
    assignment_id: int | None = None,
    employee_user_id: int | None = None,
) -> bool:
    email_key = (employee_email or "").strip().lower()
    if not email_key and not employee_user_id:
        return False
    conn = _db_connect()
    try:
        if not _table_exists(conn, "leave_requests"):
            return False
        if assignment_id:
            row = conn.execute(
                """
                SELECT 1
                FROM leave_requests
                WHERE assignment_id = ?
                  AND status IN ('pending', 'approved')
                  AND date_from <= ?
                  AND date_to >= ?
                LIMIT 1
                """,
                (assignment_id, date_to, date_from),
            ).fetchone()
            return row is not None
        if employee_user_id:
            row = conn.execute(
                """
                SELECT 1
                FROM leave_requests
                WHERE employee_user_id = ?
                  AND status IN ('pending', 'approved')
                  AND date_from <= ?
                  AND date_to >= ?
                LIMIT 1
                """,
                (employee_user_id, date_to, date_from),
            ).fetchone()
            return row is not None
        row = conn.execute(
            """
            SELECT 1
            FROM leave_requests
            WHERE lower(employee_email) = ?
              AND status IN ('pending', 'approved')
              AND date_from <= ?
              AND date_to >= ?
            LIMIT 1
            """,
            (email_key, date_to, date_from),
        ).fetchone()
        return row is not None
    finally:
        conn.close()


def _get_supervisor_site_ids(user_id: int) -> set[int]:
    conn = _db_connect()
    try:
        if not _table_exists(conn, "supervisor_sites"):
            return set()
        cur = conn.execute(
            "SELECT site_id FROM supervisor_sites WHERE supervisor_user_id = ?",
            (user_id,),
        )
        return {int(row["site_id"]) for row in cur.fetchall()}
    finally:
        conn.close()


def _get_supervisor_shift_ids(user_id: int) -> set[tuple[int, int]]:
    site_ids = sorted(_get_supervisor_site_ids(user_id))
    if not site_ids:
        return set()
    conn = _db_connect()
    try:
        if not _table_exists(conn, "assignments"):
            return set()
        placeholders = ",".join("?" for _ in site_ids)
        rows = conn.execute(
            f"""
            SELECT DISTINCT shift_id, site_id
            FROM assignments
            WHERE status = 'ACTIVE'
              AND shift_id IS NOT NULL
              AND site_id IN ({placeholders})
            """,
            tuple(site_ids),
        ).fetchall()
        return {
            (int(_row_get(row, "shift_id", 0) or 0), int(_row_get(row, "site_id", 0) or 0))
            for row in rows
            if int(_row_get(row, "shift_id", 0) or 0) > 0 and int(_row_get(row, "site_id", 0) or 0) > 0
        }
    finally:
        conn.close()


def _approver_scope_emails(user: User | None) -> set[str] | None:
    if not user:
        return set()
    if user.role == "hr_superadmin":
        return None
    client_scope = _approver_client_scope_id(user)
    if client_scope:
        today = _today_key()
        emails: set[str] = set()
        for row in _list_active_assignments(today):
            if int(_row_get(row, "client_id") or 0) == client_scope:
                email = (_row_get(row, "employee_email") or "").strip().lower()
                if email:
                    emails.add(email)
        return emails
    site_ids = _get_supervisor_site_ids(user.id)
    if not site_ids:
        return set()
    today = _today_key()
    emails: set[str] = set()
    for row in _list_active_assignments(today):
        if int(_row_get(row, "site_id") or 0) in site_ids:
            email = (_row_get(row, "employee_email") or "").strip().lower()
            if email:
                emails.add(email)
    return emails


def _approver_can_handle(user: User | None, employee_email: str = "", record: dict | None = None) -> bool:
    if not user:
        return False
    if user.role == "hr_superadmin":
        return True
    if record:
        client_scope = _approver_client_scope_id(user)
        if client_scope:
            return int(_row_get(record, "client_id") or 0) == int(client_scope)
        site_ids = _get_supervisor_site_ids(user.id)
        if site_ids:
            return int(_row_get(record, "site_id") or _row_get(record, "branch_id") or 0) in site_ids
    scope = _approver_scope_emails(user)
    if scope is None:
        return True
    return employee_email.strip().lower() in scope


def _create_leave_request(
    employee_email: str,
    employee_id: int,
    employee_user_id: int,
    assignment_id: int,
    client_id: int,
    site_id: int,
    leave_type: str,
    date_from: str,
    date_to: str,
    reason: str,
    attachment: str | None,
    attachment_path: str | None,
) -> int:
    now_ts = _now_ts()
    conn = _db_connect()
    try:
        conn.execute("BEGIN IMMEDIATE")
        overlap = conn.execute(
            """
            SELECT 1
            FROM leave_requests
            WHERE (
                    (assignment_id = ? AND ? IS NOT NULL)
                 OR (employee_user_id = ? AND ? IS NOT NULL)
                 OR lower(employee_email) = ?
            )
              AND status IN ('pending', 'approved')
              AND date_from <= ?
              AND date_to >= ?
            LIMIT 1
            """,
            (
                assignment_id,
                assignment_id,
                employee_user_id,
                employee_user_id,
                (employee_email or "").strip().lower(),
                date_to,
                date_from,
            ),
        ).fetchone()
        if overlap:
            conn.rollback()
            raise DuplicateSubmissionError("Rentang izin sudah memiliki pengajuan aktif.")
        cur = conn.execute(
            """
            INSERT INTO leave_requests (
                employee_id, employee_user_id, assignment_id, employee_email,
                client_id, site_id, client_id_snapshot, site_id_snapshot,
                branch_id, leave_type, date_from, date_to, reason,
                attachment, attachment_path, status, created_at, updated_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                employee_id,
                employee_user_id,
                assignment_id,
                employee_email,
                client_id,
                site_id,
                client_id,
                site_id,
                site_id,
                leave_type,
                date_from,
                date_to,
                reason,
                attachment,
                attachment_path,
                "pending",
                now_ts,
                now_ts,
            ),
        )
        request_id = int(cur.lastrowid)
        conn.commit()
        return request_id
    except sqlite3.IntegrityError as exc:
        conn.rollback()
        raise DuplicateSubmissionError("Rentang izin sudah memiliki pengajuan aktif.") from exc
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()


