def _list_leave_pending(user: User | None = None, limit: int | None = None) -> list[dict]:
    start = time.perf_counter()
    if limit is None and PENDING_LIST_LIMIT > 0:
        limit = PENDING_LIST_LIMIT
    conn = _db_connect()
    try:
        if not _table_exists(conn, "leave_requests"):
            return []
        scope = _approver_scope_emails(user)
        if scope is not None:
            if not scope:
                return []
            placeholders = ",".join("?" for _ in scope)
            params = [*sorted(scope)]
            query = f"""
                SELECT
                    id,
                    employee_id,
                    employee_user_id,
                    assignment_id,
                    employee_email,
                    client_id,
                    site_id,
                    client_id_snapshot,
                    site_id_snapshot,
                    branch_id,
                    leave_type AS type,
                    date_from,
                    date_to,
                    reason,
                    attachment,
                    attachment_path,
                    status,
                    approver_email AS approver,
                    approved_by_id,
                    approved_by_role,
                    approved_at,
                    note,
                    created_at,
                    updated_at
                FROM leave_requests
                WHERE status = 'pending'
                  AND lower(employee_email) IN ({placeholders})
                ORDER BY created_at DESC
            """
            if limit:
                query += " LIMIT ?"
                params.append(limit)
            cur = conn.execute(query, params)
        else:
            query = """
                SELECT
                    id,
                    employee_id,
                    employee_user_id,
                    assignment_id,
                    employee_email,
                    client_id,
                    site_id,
                    client_id_snapshot,
                    site_id_snapshot,
                    branch_id,
                    leave_type AS type,
                    date_from,
                    date_to,
                    reason,
                    attachment,
                    attachment_path,
                    status,
                    approver_email AS approver,
                    approved_by_id,
                    approved_by_role,
                    approved_at,
                    note,
                    created_at,
                    updated_at
                FROM leave_requests
                WHERE status = 'pending'
                ORDER BY created_at DESC
            """
            params: tuple = ()
            if limit:
                query += " LIMIT ?"
                params = (limit,)
            cur = conn.execute(query, params)
        rows = [dict(row) for row in cur.fetchall()]
        _perf_log("list_leave_pending", start, f"rows={len(rows)}")
        return rows
    finally:
        conn.close()


