def _approve_manual_request_atomic(
    request_id: int,
    reviewer: User,
    note: str | None,
) -> tuple[bool, str]:
    conn = _db_connect()
    try:
        conn.execute("BEGIN IMMEDIATE")
        row = conn.execute(
            "SELECT * FROM manual_attendance_requests WHERE id = ?",
            (request_id,),
        ).fetchone()
        if not row:
            conn.rollback()
            return False, "Data manual attendance tidak ditemukan."
        if row["status"] != "PENDING":
            conn.rollback()
            return False, "Manual attendance sudah diproses."
        action = _normalize_attendance_action(row["action"])
        existing_rows = conn.execute(
            """
            SELECT action FROM attendance
            WHERE lower(employee_email) = ? AND date = ?
            """,
            ((row["employee_email"] or "").strip().lower(), row["date"]),
        ).fetchall()
        exists = any(_normalize_attendance_action(existing["action"]) == action for existing in existing_rows)
        if exists:
            conn.rollback()
            return False, "Attendance harian sudah tercatat."
        conn.execute(
            "UPDATE manual_attendance_requests SET status = ?, reviewed_by_user_id = ?, reviewed_at = ?, review_note = ? WHERE id = ?",
            ("APPROVED", reviewer.email, _now_ts(), note, request_id),
        )
        client_id = row["client_id"] if "client_id" in row.keys() else None
        branch_id = row["branch_id"] if "branch_id" in row.keys() else None
        if client_id is None and branch_id is None:
            client_id, branch_id = _enterprise_scope_for_employee_email(row["employee_email"])
        conn.execute(
            "INSERT INTO attendance (employee_id, client_id, branch_id, employee_name, employee_email, date, time, action, method, selfie_path, source, manual_request_id, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
            (
                row["employee_id"],
                client_id,
                branch_id,
                row["employee_name"],
                row["employee_email"],
                row["date"],
                row["time"],
                action,
                "manual",
                None,
                "manual_request",
                row["id"],
                _now_ts(),
            ),
        )
        conn.commit()
        return True, ""
    except sqlite3.IntegrityError:
        conn.rollback()
        return False, "Attendance harian sudah tercatat."
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()


def _employee_conflict(
    email: str,
    nik: str,
    no_hp: str,
    exclude_id: int | None = None,
) -> str | None:
    conn = _db_connect()
    try:
        if not _table_exists(conn, "employees"):
            return None
        params = {"exclude_id": exclude_id or 0}
        if email:
            row = conn.execute(
                """
                SELECT id FROM employees
                WHERE lower(email) = ? AND id != ?
                LIMIT 1
                """,
                (email.lower(), params["exclude_id"]),
            ).fetchone()
            if row:
                return "Email pegawai sudah terdaftar."
        if nik:
            row = conn.execute(
                """
                SELECT id FROM employees
                WHERE nik = ? AND id != ?
                LIMIT 1
                """,
                (nik, params["exclude_id"]),
            ).fetchone()
            if row:
                return "NIK pegawai sudah terdaftar."
        normalized = _normalize_phone(no_hp)
        if normalized:
            cur = conn.execute(
                """
                SELECT id, no_hp
                FROM employees
                WHERE id != ?
                """,
                (params["exclude_id"],),
            )
            for row in cur.fetchall():
                if _normalize_phone(row["no_hp"]) == normalized:
                    return "No telp pegawai sudah terdaftar."
        return None
    finally:
        conn.close()


