def _create_patrol_tour(
    *,
    route: dict,
    assignment: dict,
    employee: dict | None,
    user: User,
    total_checkpoints: int,
) -> dict:
    now_ts = _now_ts()
    flags = _patrol_security_flags(route)
    conn = _db_connect()
    try:
        cur = conn.execute(
            """
            INSERT INTO patrol_tours (
                route_id, assignment_id, employee_user_id, employee_id, employee_email,
                site_id, client_id, shift_id, date, started_at, ended_at, status,
                total_checkpoints, completed_checkpoints,
                scan_mode, strict_mode, require_selfie, require_gps, min_scan_interval_seconds,
                invalid_reasons_json, created_at, updated_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                _row_get(route, "id"),
                _row_get(assignment, "id"),
                user.id,
                _row_get(employee, "id"),
                user.email,
                _row_get(assignment, "site_id"),
                _row_get(route, "client_id"),
                _row_get(assignment, "shift_id"),
                _today_key(),
                now_ts,
                None,
                PATROL_STATUS_ONGOING,
                total_checkpoints,
                0,
                flags["scan_mode"],
                1 if flags["strict_mode"] else 0,
                1 if flags["require_selfie"] else 0,
                1 if flags["require_gps"] else 0,
                flags["min_scan_interval_seconds"],
                None,
                now_ts,
                now_ts,
            ),
        )
        tour_id = int(cur.lastrowid)
    finally:
        conn.commit()
        conn.close()
    _sync_patrol_session_from_tour(tour_id)
    return _patrol_tour_by_id(tour_id) or {"id": tour_id}


def _patrol_completion_percent(completed_checkpoints: int | None, total_checkpoints: int | None) -> float:
    total = int(total_checkpoints or 0)
    completed = int(completed_checkpoints or 0)
    if total <= 0:
        return 0.0
    return round(max(0, min(completed, total)) * 100 / total, 2)


def _sync_patrol_session_from_tour(tour_id: int) -> None:
    tour = _patrol_tour_by_id(tour_id)
    if not tour:
        return
    employee_id = int(_row_get(tour, "employee_id") or 0)
    assignment_id = int(_row_get(tour, "assignment_id") or 0)
    site_id = int(_row_get(tour, "site_id") or 0)
    if not employee_id or not assignment_id or not site_id:
        return
    percent = _patrol_completion_percent(
        int(_row_get(tour, "completed_checkpoints") or 0),
        int(_row_get(tour, "total_checkpoints") or 0),
    )
    conn = _db_connect()
    try:
        conn.execute(
            """
            INSERT INTO patrol_sessions (
                id, employee_id, employee_user_id, assignment_id, site_id, client_id,
                start_time, end_time, status, completion_percent, created_at, updated_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(id) DO UPDATE SET
                employee_id = excluded.employee_id,
                employee_user_id = excluded.employee_user_id,
                assignment_id = excluded.assignment_id,
                site_id = excluded.site_id,
                client_id = excluded.client_id,
                start_time = excluded.start_time,
                end_time = excluded.end_time,
                status = excluded.status,
                completion_percent = excluded.completion_percent,
                updated_at = excluded.updated_at
            """,
            (
                int(_row_get(tour, "id") or tour_id),
                employee_id,
                int(_row_get(tour, "employee_user_id") or 0) or None,
                assignment_id,
                site_id,
                int(_row_get(tour, "client_id") or 0) or None,
                _row_get(tour, "started_at"),
                _row_get(tour, "ended_at"),
                _row_get(tour, "status") or PATROL_STATUS_ONGOING,
                percent,
                _row_get(tour, "created_at") or _now_ts(),
                _now_ts(),
            ),
        )
    finally:
        conn.commit()
        conn.close()


def _append_patrol_invalid_reason(existing_json: str | None, reason: str) -> str:
    clean_reason = (reason or "").strip()
    reasons: list[str] = []
    if existing_json:
        try:
            parsed = json.loads(existing_json)
            if isinstance(parsed, list):
                reasons = [str(item).strip() for item in parsed if str(item).strip()]
        except json.JSONDecodeError:
            reasons = []
    if clean_reason and clean_reason not in reasons:
        reasons.append(clean_reason)
    return json.dumps(reasons, ensure_ascii=True)


def _update_patrol_tour_state(
    tour_id: int,
    *,
    status: str | None = None,
    completed_checkpoints: int | None = None,
    ended_at: str | None = None,
    append_reason: str | None = None,
) -> bool:
    updated = False
    conn = _db_connect()
    try:
        if not _table_exists(conn, "patrol_tours"):
            return False
        conn.execute("BEGIN IMMEDIATE")
        row = conn.execute(
            "SELECT id, status, invalid_reasons_json FROM patrol_tours WHERE id = ?",
            (tour_id,),
        ).fetchone()
        if not row:
            conn.rollback()
            return False
        current_status = (_row_get(row, "status") or "").lower()
        if current_status in {PATROL_STATUS_COMPLETED, PATROL_STATUS_INVALID, PATROL_STATUS_INCOMPLETE}:
            conn.rollback()
            return False
        updates: list[str] = []
        params: list = []
        if status:
            updates.append("status = ?")
            params.append(status)
        if completed_checkpoints is not None:
            updates.append("completed_checkpoints = ?")
            params.append(max(0, completed_checkpoints))
        if ended_at is not None:
            updates.append("ended_at = ?")
            params.append(ended_at)
        if append_reason:
            merged = _append_patrol_invalid_reason(row["invalid_reasons_json"], append_reason)
            updates.append("invalid_reasons_json = ?")
            params.append(merged)
        updates.append("updated_at = ?")
        params.append(_now_ts())
        params.append(tour_id)
        cur = conn.execute(
            f"UPDATE patrol_tours SET {', '.join(updates)} WHERE id = ?",
            tuple(params),
        )
        updated = cur.rowcount == 1
        conn.commit()
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()
    if updated:
        _sync_patrol_session_from_tour(tour_id)
    return updated


def _insert_patrol_scan(
    *,
    tour_id: int,
    route_id: int,
    employee_email: str,
    checkpoint_id: int | None,
    checkpoint_sequence: int | None,
    expected_sequence: int | None,
    is_expected_sequence: bool,
    method: str,
    scan_payload: str,
    timestamp_value: str,
    lat: float | None,
    lng: float | None,
    gps_distance_m: float | None,
    gps_valid: bool,
    selfie_path: str | None,
    selfie_required: bool,
    selfie_valid: bool,
    interval_seconds: int | None,
    validation_status: str,
    validation_note: str | None,
) -> int:
    conn = _db_connect()
    scan_id = 0
    try:
        if not _table_exists(conn, "patrol_scans"):
            return 0
        cur = conn.execute(
            """
            INSERT INTO patrol_scans (
                tour_id, route_id, employee_email,
                checkpoint_id, checkpoint_sequence, expected_sequence, is_expected_sequence,
                method, scan_payload, timestamp,
                lat, lng, gps_distance_m, gps_valid,
                selfie_path, selfie_required, selfie_valid,
                interval_seconds, validation_status, validation_note,
                created_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                tour_id,
                route_id,
                employee_email,
                checkpoint_id,
                checkpoint_sequence,
                expected_sequence,
                1 if is_expected_sequence else 0,
                method,
                scan_payload,
                timestamp_value,
                lat,
                lng,
                gps_distance_m,
                1 if gps_valid else 0,
                selfie_path,
                1 if selfie_required else 0,
                1 if selfie_valid else 0,
                interval_seconds,
                validation_status,
                validation_note,
                _now_ts(),
            ),
        )
        scan_id = int(cur.lastrowid)
    except sqlite3.IntegrityError:
        conn.rollback()
        raise
    finally:
        if scan_id:
            conn.commit()
        conn.close()
    _insert_patrol_log_from_scan(
        source_scan_id=scan_id,
        session_id=tour_id,
        checkpoint_id=checkpoint_id,
        scanned_at=timestamp_value,
        lat=lat,
        lon=lng,
        validation_status=validation_status,
        is_expected_sequence=is_expected_sequence,
    )
    return scan_id


